		filter: progid:DXImageTransform.Microsoft.gradient(startColorstr = '#00FFFFFF', endColorstr = 'white', GradientType = 0);
	}

	.tcp-widget .a-switch-row .a-switch-label {
		color: var(--text-muted);
	}

	.tcp-widget .a-switch-row.a-disabled.a-active .a-switch-control:active {
		border-color: var(--border-color-hover);
	}

	.tcp-widget .a-switch-row.a-disabled .a-switch-control:active {
		border-color: var(--border-color-hover);
	}

	.tcp-widget .a-switch-row:hover .a-switch-control {
		border-color: var(--border-color-hover);
	}

	.tcp-widget .a-switch-row.a-disabled:hover .a-switch-control {
		border-color: var(--border-color-hover);
	}

	.tcp-widget .a-switch-row.a-disabled:hover.a-active .a-switch-control {
		border-color: var(--border-color-hover);
	}

	.tcp-widget .a-switch {
		border: 1px solid var(--border-color);
		border-top-color: var(--text-muted);
		background-color: var(--bg-tertiary);
		box-shadow: var(--shadow-drop);
	}

	.tcp-widget .a-switch-control {
		border: 1px solid var(--border-color);
		border-top-color: var(--text-muted);
		border-bottom-color: var(--text-muted);
		background: var(--bg-primary);

		filter: progid:DXImageTransform.Microsoft.gradient(startColorstr = '#eff1f3', endColorstr = 'white', GradientType = 0);
		box-shadow: var(--shadow-drop);
	}

	.tcp-widget .a-switch-control:active {
		border-color: var(--border-color-hover);
	}

	.tcp-widget .a-active .a-switch {
		background-color: var(--bg-primary);
		border-color: var(--border-color);
	}

	.tcp-widget .a-active .a-switch-control {
		border-color: var(--border-color);
	}

	.tcp-widget .a-active .a-switch-label {
		color: var(--text-muted);
	}

	.tcp-widget .a-no-js .a-switch-row .a-switch-label {
		color: var(--text-muted);
	}

	.tcp-widget .a-carousel-button:focus {
		border-color: var(--border-color-hover);
	}

	.tcp-widget ol.a-carousel {
		color: var(--text-muted);
	}

	.tcp-widget #header .header-leftpanel .menuWrapper .labelBox .labelList .labelListItem {
		filter: var(--filter-icon);
	}
}"}

{"title":"iiio","content":"// ====================================================================
// DYNAMICZNE TWORZENIE STRUKTURY FORMULARZA CMR
// ====================================================================

function createCMRForm() {
    // Główny kontener layout
    const mainLayout = document.createElement('div');
    mainLayout.className = 'main-layout';

    // ============================================================
    // FORMULARZ BOCZNY (SIDEBAR)
    // ============================================================
    const sidebar = document.createElement('div');
    sidebar.id = 'intro-sidebar';

    const introForm = document.createElement('div');
    introForm.className = 'intro-form';

    // Tytuł
    const title = document.createElement('h1');
    title.className = 'intro-title';
    title.textContent = 'KREATOR CMR';
    introForm.appendChild(title);

    // Przycisk przełączania motywu
    const themeToggle = document.createElement('button');
    themeToggle.type = 'button';
    themeToggle.id = 'theme-toggle';
    themeToggle.style.borderRadius = '0';
    themeToggle.innerHTML = '<img src="https://api.iconify.design/duo-icons:moon-stars.svg" id="theme-icon" alt="theme">';
    introForm.appendChild(themeToggle);


    // ============================================================
    // SEKCJA: ODBIORCA (pole 6)
    // ============================================================
    const consigneeWrapper = document.createElement('div');
    consigneeWrapper.className = 'consignee-field-wrapper';

    const consigneeSectionTitle = document.createElement('div');
    consigneeSectionTitle.className = 'form-section-title';
    consigneeSectionTitle.innerHTML = '<i class="fas fa-map-marker-alt"></i> Kierunek';
    consigneeWrapper.appendChild(consigneeSectionTitle);

    const consigneeFieldDiv = document.createElement('div');
    consigneeFieldDiv.className = 'intro-field';

    const consigneeLabelContainer = document.createElement('div');
    consigneeLabelContainer.className = 'consignee-label-container';

    const consigneeLabel = document.createElement('label');
    consigneeLabel.setAttribute('for', 'intro_consignee');
    consigneeLabel.textContent = 'ODBIORCA:';
    consigneeLabelContainer.appendChild(consigneeLabel);

    const directionCounter = document.createElement('span');
    directionCounter.id = 'direction-counter';
    directionCounter.textContent = `Kierunków: ${kierunki.length}`;
    consigneeLabelContainer.appendChild(directionCounter);

    const manageDirectionsBtn = document.createElement('button');
    manageDirectionsBtn.type = 'button';
    manageDirectionsBtn.className = 'manage-directions-btn';
    manageDirectionsBtn.style.borderRadius = '0';
    manageDirectionsBtn.innerHTML = '<img src="https://api.iconify.design/lets-icons:setting-line-duotone.svg" alt="settings" style="width: 20px; height: 20px;">';
    manageDirectionsBtn.title = 'Zarządzaj kierunkami';
    manageDirectionsBtn.onclick = () => showManageDirectionsModal();
    consigneeLabelContainer.appendChild(manageDirectionsBtn);

    consigneeFieldDiv.appendChild(consigneeLabelContainer);

    const flexContainer = document.createElement('div');
    flexContainer.className = 'search-nat-container';

    const searchColumn = document.createElement('div');

    const searchLabel = document.createElement('label');
    searchLabel.className = 'small-label';
    searchLabel.setAttribute('for', 'intro_search');
    searchLabel.textContent = 'Szukaj:';
    searchColumn.appendChild(searchLabel);

    const searchInputWrapper = document.createElement('div');
    searchInputWrapper.className = 'field-relative-wrapper';

    const searchInput = document.createElement('input');
    searchInput.type = 'text';
    searchInput.id = 'intro_search';
    searchInput.style.borderRadius = '0';
    searchInput.className = 'search-input field-with-clear-btn';
    searchInput.placeholder = 'WRO1...';
    searchInputWrapper.appendChild(searchInput);

    const searchClearBtn = document.createElement('button');
    searchClearBtn.type = 'button';
    searchClearBtn.className = 'clear-btn';
    searchClearBtn.id = 'clear_intro_search';
    searchClearBtn.style.display = 'none';
    searchClearBtn.style.borderRadius = '0';
    searchClearBtn.textContent = '✕';
    searchClearBtn.onclick = function () {
        const introConsigneeTextarea = document.getElementById('intro_consignee');
        const introNationalsInput = document.getElementById('intro_nationals');
        const selectElement = document.getElementById('intro_consignee_select');

        document.getElementById('intro_search').value = '';
        introConsigneeTextarea.value = '';
        introNationalsInput.value = '';

        selectElement.classList.remove('visible');

        searchInput.dispatchEvent(new Event('input'));
        introConsigneeTextarea.dispatchEvent(new Event('input', { bubbles: true }));
        introNationalsInput.dispatchEvent(new Event('input', { bubbles: true }));

        this.style.display = 'none';
    };
    searchInputWrapper.appendChild(searchClearBtn);

    searchColumn.appendChild(searchInputWrapper);
    flexContainer.appendChild(searchColumn);

    const natColumn = document.createElement('div');

    const natLabel = document.createElement('label');
    natLabel.setAttribute('for', 'intro_nationals');
    natLabel.className = 'small-label';
    natLabel.textContent = 'NAT:';
    natColumn.appendChild(natLabel);

    const natInput = document.createElement('input');
    natInput.type = 'text';
    natInput.id = 'intro_nationals';
    natInput.style.borderRadius = '0';
    natInput.className = 'nat-input';
    natInput.placeholder = 'TYPE';
    natColumn.appendChild(natInput);

    flexContainer.appendChild(natColumn);
    consigneeFieldDiv.appendChild(flexContainer);

    const select = document.createElement('select');
    select.id = 'intro_consignee_select';
    select.size = 2;
    select.style.borderRadius = '0';
    select.className = 'intro-field';
    const defaultOption = document.createElement('option');
    defaultOption.value = '';
    defaultOption.textContent = '-- Wybierz kierunek --';
    select.appendChild(defaultOption);
    consigneeFieldDiv.appendChild(select);

    const consigneeTextareaDiv = document.createElement('div');
    consigneeTextareaDiv.className = 'field-relative-wrapper';

    const consigneeTextarea = document.createElement('textarea');
    consigneeTextarea.id = 'intro_consignee';
    consigneeTextarea.rows = 3;
    consigneeTextarea.style.borderRadius = '0';
    consigneeTextarea.placeholder = 'Lub wpisz adres...';
    consigneeTextarea.className = 'consignee-textarea field-with-clear-btn';
    consigneeTextareaDiv.appendChild(consigneeTextarea);

    const consigneeClearBtn = document.createElement('button');
    consigneeClearBtn.type = 'button';
    consigneeClearBtn.className = 'clear-btn clear-btn-top-14';
    consigneeClearBtn.id = 'clear_intro_consignee';
    consigneeClearBtn.style.display = 'none';
    consigneeClearBtn.style.borderRadius = '0';
    consigneeClearBtn.textContent = '✕';
    consigneeClearBtn.onclick = function () {
        consigneeTextarea.value = '';
        consigneeTextarea.dispatchEvent(new Event('input'));
        this.style.display = 'none';
    };
    consigneeTextareaDiv.appendChild(consigneeClearBtn);

    consigneeFieldDiv.appendChild(consigneeTextareaDiv);
    consigneeWrapper.appendChild(consigneeFieldDiv);
    introForm.appendChild(consigneeWrapper);

    // ============================================================
    // SEKCJA: DANE PODSTAWOWE (pola 1-5)
    // ============================================================
    const basicSection = document.createElement('div');
    basicSection.className = 'form-section';

    const basicSectionTitle = document.createElement('div');
    basicSectionTitle.className = 'form-section-title';
    basicSectionTitle.innerHTML = '<i class="fas fa-clipboard-list"></i> Dane Podstawowe';
    basicSection.appendChild(basicSectionTitle);

    function createField(id, label, placeholder, type = 'input', rows = 3, topPosition = null) {
        const fieldDiv = document.createElement('div');
        fieldDiv.className = 'intro-field';

        const labelEl = document.createElement('label');
        labelEl.setAttribute('for', `intro_${id}`);
        labelEl.textContent = label;
        fieldDiv.appendChild(labelEl);

        const relativeDiv = document.createElement('div');
        relativeDiv.className = 'field-relative-wrapper';

        let field;
        if (type === 'textarea') {
            field = document.createElement('textarea');
            field.rows = rows;
        } else {
            field = document.createElement('input');
            field.type = 'text';
        }
        field.id = `intro_${id}`;
        field.placeholder = placeholder;
        field.className = 'field-with-clear-btn';
        field.style.borderRadius = '0';
        relativeDiv.appendChild(field);

        const clearBtn = document.createElement('button');
        clearBtn.type = 'button';
        clearBtn.className = 'clear-btn';
        if (topPosition) clearBtn.classList.add('clear-btn-top-14');
        clearBtn.id = `clear_intro_${id}`;
        clearBtn.style.display = 'none';
        clearBtn.style.borderRadius = '0';
        clearBtn.textContent = '✕';
        clearBtn.onclick = function () {
            field.value = '';
            field.dispatchEvent(new Event('input'));
            this.style.display = 'none';
        };
        relativeDiv.appendChild(clearBtn);

        fieldDiv.appendChild(relativeDiv);
        return fieldDiv;
    }

    const row1 = document.createElement('div');
    row1.className = 'field-row';
    row1.appendChild(createField('vrid', 'VRID:', 'VRID...'));
    row1.appendChild(createField('seal', 'SEAL:', 'Seal...'));
    basicSection.appendChild(row1);

    const row2 = document.createElement('div');
    row2.className = 'field-row';
    row2.appendChild(createField('tractor', 'TRACTOR:', 'Ciągnik...'));
    row2.appendChild(createField('trailer', 'TRAILER:', 'Naczepa...'));
    basicSection.appendChild(row2);

    const descriptionField = createField('description', 'OPIS:', 'Opis...', 'textarea', 3, '14px');

    const buttonContainer = document.createElement('div');
    buttonContainer.className = 'opis-buttons-container';

    const btn1 = document.createElement('button');
    btn1.type = 'button';
    btn1.className = 'opis-btn';
    btn1.style.borderRadius = '0';
    btn1.innerHTML = '<i class="fas fa-file-alt"></i> Opisy';
    btn1.onclick = () => showOpisyModal();
    buttonContainer.appendChild(btn1);

    const btn2 = document.createElement('button');
    btn2.type = 'button';
    btn2.className = 'opis-btn';
    btn2.style.borderRadius = '0';
    btn2.innerHTML = '<i class="fas fa-truck"></i> Spedycyjne';
    btn2.onclick = () => showOpisySpedycyjneModal();
    buttonContainer.appendChild(btn2);

    descriptionField.appendChild(buttonContainer);
    basicSection.appendChild(descriptionField);

    introForm.appendChild(basicSection);

    // ============================================================
    // SEKCJA: AKCJE
    // ============================================================
    const actionsSection = document.createElement('div');
    actionsSection.className = 'form-section';

    const actionsSectionTitle = document.createElement('div');
    actionsSectionTitle.className = 'form-section-title';
    actionsSectionTitle.innerHTML = '<i class="fas fa-bolt"></i> Akcje';
    actionsSection.appendChild(actionsSectionTitle);

    const templateSelector = document.createElement('div');
    templateSelector.className = 'template-selector';

    const templateLabel = document.createElement('label');
    templateLabel.className = 'template-label';
    templateLabel.innerHTML = '<i class="fas fa-file-alt"></i> Szablon:';
    templateSelector.appendChild(templateLabel);

    const templateOptions = document.createElement('div');
    templateOptions.className = 'template-options';

    const cmrRadioWrapper = document.createElement('label');
    cmrRadioWrapper.className = 'template-radio-wrapper';
    cmrRadioWrapper.style.borderRadius = '0';

    const cmrRadio = document.createElement('input');
    cmrRadio.type = 'radio';
    cmrRadio.name = 'template';
    cmrRadio.value = 'cmr';
    cmrRadio.id = 'template_cmr';
    const savedTemplate = localStorage.getItem('selected_template') || 'cmr';
    cmrRadio.checked = savedTemplate === 'cmr';

    const cmrLabel = document.createElement('span');
    cmrLabel.textContent = 'CMR';

    cmrRadioWrapper.appendChild(cmrRadio);
    cmrRadioWrapper.appendChild(cmrLabel);
    templateOptions.appendChild(cmrRadioWrapper);

    const f1RadioWrapper = document.createElement('label');
    f1RadioWrapper.className = 'template-radio-wrapper';
    f1RadioWrapper.style.borderRadius = '0';

    const f1Radio = document.createElement('input');
    f1Radio.type = 'radio';
    f1Radio.name = 'template';
    f1Radio.value = 'f1';
    f1Radio.id = 'template_f1';
    f1Radio.checked = savedTemplate === 'f1';

    const f1Label = document.createElement('span');
    f1Label.textContent = 'F1';

    f1RadioWrapper.appendChild(f1Radio);
    f1RadioWrapper.appendChild(f1Label);
    templateOptions.appendChild(f1RadioWrapper);

    function updateFieldsState(templateValue) {
        const vridField = document.getElementById('intro_vrid');
        const tractorField = document.getElementById('intro_tractor');
        const consigneeField = document.getElementById('intro_consignee');
        const nationalsField = document.getElementById('intro_nationals');
        const searchField = document.getElementById('intro_search');

        if (templateValue === 'f1') {
            vridField.disabled = true;
            tractorField.disabled = true;
            consigneeField.disabled = true;
            nationalsField.disabled = true;
            searchField.disabled = true;

            [vridField, tractorField, consigneeField, nationalsField, searchField].forEach(field => {
                field.classList.add('field-disabled');
            });
        } else {
            vridField.disabled = false;
            tractorField.disabled = false;
            consigneeField.disabled = false;
            nationalsField.disabled = false;
            searchField.disabled = false;

            [vridField, tractorField, consigneeField, nationalsField, searchField].forEach(field => {
                field.classList.remove('field-disabled');
            });
        }
    }

    [cmrRadio, f1Radio].forEach(radio => {
        radio.addEventListener('change', () => {
            localStorage.setItem('selected_template', radio.value);
            updateFieldsState(radio.value);
            [cmrRadioWrapper, f1RadioWrapper].forEach(w => {
                const r = w.querySelector('input[type="radio"]');
                if (r.checked) {
                    w.classList.add('active');
                } else {
                    w.classList.remove('active');
                }
            });
        });
    });

    setTimeout(() => {
        [cmrRadioWrapper, f1RadioWrapper].forEach(w => {
            const r = w.querySelector('input[type="radio"]');
            if (r.checked) {
                w.classList.add('active');
            } else {
                w.classList.remove('active');
            }
        });
        updateFieldsState(savedTemplate);
    }, 100);

    templateSelector.appendChild(templateOptions);
    actionsSection.appendChild(templateSelector);

    const buttonsDiv = document.createElement('div');
    buttonsDiv.className = 'buttons-container';

    const printBtn = document.createElement('button');
    printBtn.type = 'button';
    printBtn.id = 'btn_print';
    printBtn.style.borderRadius = '0';
    printBtn.innerHTML = '<img src="https://api.iconify.design/solar:printer-bold-duotone.svg?color=darkgray" style="width: 1.5em; height: 1.5em; display: block;"> DRUKUJ';
    buttonsDiv.appendChild(printBtn);

    const clearAllBtn = document.createElement('button');
    clearAllBtn.type = 'button';
    clearAllBtn.id = 'btn_clear_all';
    clearAllBtn.style.borderRadius = '0';
    clearAllBtn.innerHTML = '<i class="fas fa-trash-alt"></i> WYCZYŚĆ';
    buttonsDiv.appendChild(clearAllBtn);

    const historyBtn = document.createElement('button');
    historyBtn.type = 'button';
    historyBtn.id = 'btn_history';
    historyBtn.style.borderRadius = '0';
    historyBtn.innerHTML = '<i class="fas fa-history"></i> HISTORIA';
    buttonsDiv.appendChild(historyBtn);

    actionsSection.appendChild(buttonsDiv);

    const printInfo = document.createElement('div');
    printInfo.className = 'print-info';
    printInfo.innerHTML = '<i class="fas fa-info-circle"></i> Używa domyślnej drukarki systemowej';
    actionsSection.appendChild(printInfo);

    introForm.appendChild(actionsSection);

    sidebar.appendChild(introForm);
    mainLayout.appendChild(sidebar);
    document.body.appendChild(mainLayout);

    // ============================================================
    // MODAL HISTORII
    // ============================================================
    const modal = document.createElement('div');
    modal.id = 'history-modal';

    const modalContent = document.createElement('div');
    modalContent.style.borderRadius = '0';

    const modalHeader = document.createElement('div');
    modalHeader.className = 'history-modal-header';

    const modalTitle = document.createElement('h2');
    modalTitle.innerHTML = '<i class="fas fa-history"></i> Historia';
    modalHeader.appendChild(modalTitle);

    const headerButtons = document.createElement('div');
    headerButtons.className = 'header-buttons';

    const clearHistoryBtn = document.createElement('button');
    clearHistoryBtn.className = 'history-clear-btn';
    clearHistoryBtn.style.borderRadius = '0';
    clearHistoryBtn.innerHTML = '<i class="fas fa-trash-alt"></i> Wyczyść';
    clearHistoryBtn.onclick = () => clearHistory();
    headerButtons.appendChild(clearHistoryBtn);

    const closeBtn = document.createElement('button');
    closeBtn.className = 'history-modal-close';
    closeBtn.style.borderRadius = '0';
    closeBtn.innerHTML = '<img src="https://api.iconify.design/ant-design:close-square-twotone.svg?color=darkgray" style="width: 1.5em; height: 1.5em; vertical-align: -0.25em;">';
    closeBtn.onclick = () => modal.style.display = 'none';
    headerButtons.appendChild(closeBtn);

    modalHeader.appendChild(headerButtons);
    modalContent.appendChild(modalHeader);

    const historyList = document.createElement('div');
    historyList.id = 'history-list';
    modalContent.appendChild(historyList);

    modal.appendChild(modalContent);
    document.body.appendChild(modal);
}

// Wywołanie funkcji tworzenia formularza
createCMRForm();

// ====================================================================
// LOGIKA APLIKACJI
// ====================================================================

const selectElement = document.getElementById('intro_consignee_select');
const searchInput = document.getElementById('intro_search');

function refreshDirectionsList() {
    kierunki = getAllDirections();
}

function populateSelect(filteredKierunki) {
    selectElement.innerHTML = '<option value="">-- Wybierz kierunek --</option>';
    filteredKierunki.forEach(k => {
        const option = document.createElement('option');
        option.value = k.adres;
        const customBadge = k.custom ? ' 🏷️' : '';
        option.textContent = `${k.kod} - ${k.typ}${customBadge}`;
        option.dataset.kod = k.kod;
        option.dataset.custom = k.custom || false;
        selectElement.appendChild(option);
    });

    const counter = document.getElementById('direction-counter');
    if (counter) {
        const customCount = loadCustomDirections().length;
        if (filteredKierunki.length === kierunki.length) {
            counter.textContent = customCount > 0 ? `Kierunków: ${kierunki.length} (${customCount} własnych)` : `Kierunków: ${kierunki.length}`;
        } else {
            counter.textContent = `Znaleziono: ${filteredKierunki.length} / ${kierunki.length}`;
        }
    }
}

window.onDirectionsLoaded = function () {
    refreshDirectionsList();
    populateSelect(kierunki);
};

refreshDirectionsList();
populateSelect(kierunki);

function cleanInputValue(value) {
    return value.replace(/[\t\n\r]+/g, ' ').replace(/\s+/g, ' ').trim();
}

function cleanTextareaValue(value) {
    return value.replace(/[\t]+/g, ' ').replace(/ +/g, ' ').replace(/^ +/gm, '').replace(/ +$/gm, '').replace(/\n{3,}/g, '\n\n');
}

searchInput.addEventListener('input', function () {
    const cursorPosition = this.selectionStart;
    const oldLength = this.value.length;
    this.value = cleanInputValue(this.value).toUpperCase();
    const newLength = this.value.length;
    const diff = newLength - oldLength;
    this.setSelectionRange(cursorPosition + diff, cursorPosition + diff);

    const searchTerm = this.value;
    const filtered = kierunki.filter(k =>
        k.kod.includes(searchTerm) ||
        k.adres.toUpperCase().includes(searchTerm) ||
        k.typ.includes(searchTerm)
    );
    populateSelect(filtered);

    searchTerm.length > 0 ? selectElement.classList.add('visible') : selectElement.classList.remove('visible');

    if (filtered.length > 0 && searchTerm.length > 0) {
        selectElement.selectedIndex = 1;
        const firstMatch = filtered[0];
        const introConsigneeTextarea = document.getElementById('intro_consignee');
        const introNationalsInput = document.getElementById('intro_nationals');

        introConsigneeTextarea.value = firstMatch.adres;
        introNationalsInput.value = firstMatch.typ;

        introConsigneeTextarea.dispatchEvent(new Event('input', { bubbles: true }));
        introNationalsInput.dispatchEvent(new Event('input', { bubbles: true }));

        if (firstMatch.kod.startsWith(searchTerm)) {
            const suggestionText = firstMatch.kod.substring(searchTerm.length);
            if (suggestionText) {
                this.value = searchTerm + suggestionText;
                this.setSelectionRange(searchTerm.length, this.value.length);
            }
        }
    } else if (searchTerm.length === 0) {
        const introConsigneeTextarea = document.getElementById('intro_consignee');
        const introNationalsInput = document.getElementById('intro_nationals');
        introConsigneeTextarea.value = '';
        introNationalsInput.value = '';
        introConsigneeTextarea.dispatchEvent(new Event('input', { bubbles: true }));
        introNationalsInput.dispatchEvent(new Event('input', { bubbles: true }));
        selectElement.selectedIndex = 0;
    }
});

selectElement.addEventListener('change', function () {
    const introConsigneeTextarea = document.getElementById('intro_consignee');
    const introNationalsInput = document.getElementById('intro_nationals');
    if (this.value) {
        const selectedKierunek = kierunki.find(k => k.adres === this.value);
        introConsigneeTextarea.value = this.value;
        if (selectedKierunek) {
            introNationalsInput.value = selectedKierunek.typ;
            introNationalsInput.dispatchEvent(new Event('input', { bubbles: true }));
        }
        introConsigneeTextarea.dispatchEvent(new Event('input', { bubbles: true }));
        selectElement.classList.remove('visible');
    }
});

function updateRealTime(forceUpdate = false) {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}T${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
}

function getCurrentDate() {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
}

const inputFields = ['intro_vrid', 'intro_tractor', 'intro_trailer', 'intro_seal', 'intro_nationals'];
const textareaFields = ['intro_consignee', 'intro_description'];

inputFields.forEach(fieldId => {
    const field = document.getElementById(fieldId);
    if (field) {
        field.addEventListener('input', function () {
            const cursorPosition = this.selectionStart;
            const oldLength = this.value.length;
            this.value = cleanInputValue(this.value).toUpperCase();
            const diff = this.value.length - oldLength;
            this.setSelectionRange(cursorPosition + diff, cursorPosition + diff);
        });
    }
});

textareaFields.forEach(fieldId => {
    const field = document.getElementById(fieldId);
    if (field) {
        field.addEventListener('input', function () {
            const cursorPosition = this.selectionStart;
            const oldLength = this.value.length;
            this.value = cleanTextareaValue(this.value).toUpperCase();
            const diff = this.value.length - oldLength;
            this.setSelectionRange(cursorPosition + diff, cursorPosition + diff);
        });
    }
});

function toggleClearButton(inputId, buttonId) {
    const input = document.getElementById(inputId);
    const button = document.getElementById(buttonId);
    if (input && button) {
        input.addEventListener('input', () => {
            button.style.display = input.value.trim() ? 'block' : 'none';
        });
        button.style.display = input.value.trim() ? 'block' : 'none';
    }
}

