function saveToHistory() {
    const selectedTemplate = document.querySelector('input[name="template"]:checked').value;
    const data = {
        timestamp: new Date().toISOString(),
        template: selectedTemplate,
        vrid: document.getElementById('intro_vrid').value,
        tractor: document.getElementById('intro_tractor').value,
        trailer: document.getElementById('intro_trailer').value,
        description: document.getElementById('intro_description').value,
        seal: document.getElementById('intro_seal').value,
        consignee: document.getElementById('intro_consignee').value,
        nationals: document.getElementById('intro_nationals').value,
        loading_date: getCurrentDate(),
        signature_datetime: updateRealTime(true)
    };
    let history = JSON.parse(localStorage.getItem('cmr_history') || '[]');
    history.unshift(data);
    if (history.length > 20) history = history.slice(0, 20);
    localStorage.setItem('cmr_history', JSON.stringify(history));
}

function loadFromHistory(index) {
    const history = JSON.parse(localStorage.getItem('cmr_history') || '[]');
    if (history[index]) {
        showConfirmModal('Czy na pewno chcesz przywrócić te dane?', () => {
            const data = history[index];
            const template = data.template || 'cmr';
            const templateRadio = document.getElementById(`template_${template}`);
            if (templateRadio) {
                templateRadio.checked = true;
                localStorage.setItem('selected_template', template);
                templateRadio.dispatchEvent(new Event('change'));
            }
            ['vrid', 'tractor', 'trailer', 'description', 'seal', 'consignee', 'nationals'].forEach(id => {
                const el = document.getElementById(`intro_${id}`);
                if (el) {
                    el.value = data[id] || '';
                    el.dispatchEvent(new Event('input'));
                }
            });
            document.getElementById('history-modal').style.display = 'none';
            showSuccessModal('Dane zostały pomyślnie przywrócone!');
        }, 'PRZYWRÓĆ', 'ANULUJ');
    }
}

function clearHistory() {
    showConfirmModal('Czy na pewno chcesz wyczyścić historię?', () => {
        localStorage.removeItem('cmr_history');
        displayHistory();
        showSuccessModal('Historia wyczyszczona!');
    }, 'WYCZYŚĆ', 'ANULUJ');
}

function displayHistory() {
    const history = JSON.parse(localStorage.getItem('cmr_history') || '[]');
    const historyList = document.getElementById('history-list');
    if (history.length === 0) {
        historyList.innerHTML = '<div class="history-empty-state"><i class="fas fa-inbox"></i>Brak historii</div>';
        return;
    }
    historyList.innerHTML = '';
    history.forEach((item, index) => {
        const itemDiv = document.createElement('div');
        itemDiv.className = 'history-item';
        itemDiv.style.borderRadius = '0';
        const template = item.template || 'cmr';
        if (template === 'f1') itemDiv.classList.add('f1-border');

        const dateStr = new Date(item.timestamp).toLocaleString('pl-PL');
        itemDiv.innerHTML = `
            <div class="history-item-header">
                <div class="header-left">
                    <strong class="history-date-span"><i class="fas fa-calendar-alt"></i> ${dateStr}</strong>
                    <span class="template-badge ${template}">${template.toUpperCase()}</span>
                </div>
                <button class="history-restore-btn" style="border-radius:0;"><i class="fas fa-undo"></i> PRZYWRÓĆ</button>
            </div>
            <div class="history-item-details">
                ${template === 'f1' ? 
                    `<div><strong>Naczepa:</strong> ${item.trailer || '-'}</div><div><strong>Seal:</strong> ${item.seal || '-'}</div>` :
                    `<div><strong>VRID:</strong> ${item.vrid || '-'}</div><div><strong>Ciągnik:</strong> ${item.tractor || '-'}</div><div><strong>Naczepa:</strong> ${item.trailer || '-'}</div>`
                }
            </div>
        `;
        itemDiv.querySelector('.history-restore-btn').onclick = () => loadFromHistory(index);
        historyList.appendChild(itemDiv);
    });
}

