function getBasicFields() {
    return [
        document.getElementById('intro_vrid'),
        document.getElementById('intro_tractor'),
        document.getElementById('intro_trailer'),
        document.getElementById('intro_seal')
    ].filter(Boolean);
}

var lastAppliedPasteValue = '';
var lastAppliedPasteTime = 0;
var PASTE_APPLY_DEBOUNCE_MS = 400;

function applyPasteFromPage(data) {
    const fields = getBasicFields();
    if (fields.length !== 4 || !data) return;

    if (data.value !== undefined) {
        const value = String(data.value).trim();
        var now = Date.now();
        if (value === lastAppliedPasteValue && (now - lastAppliedPasteTime) < PASTE_APPLY_DEBOUNCE_MS) return;
        lastAppliedPasteValue = value;
        lastAppliedPasteTime = now;

        chrome.storage.local.get('nextBasicFieldIndex', (result) => {
            const idx = (result.nextBasicFieldIndex ?? 0) % 4;
            fields[idx].value = value;
            fields[idx].dispatchEvent(new Event('input'));

            // Inteligentne wykrywanie kierunku z wklejonej wartości
            if (value.includes('->')) {
                const parts = value.split('->');
                if (parts.length > 1) {
                    const dest = parts[1].trim();
                    const sInput = document.getElementById('intro_search');
                    if (sInput) {
                        sInput.value = dest;
                        sInput.dispatchEvent(new Event('input'));
                    }
                }
            }

            chrome.storage.local.set({ nextBasicFieldIndex: (idx + 1) % 4 });
            fields[(idx + 1) % 4].focus();
        });
        return;
    }

    if (data.vrid !== undefined) {
        fields[0].value = data.vrid || '';
        fields[1].value = data.tractor || '';
        fields[2].value = data.trailer || '';
        fields[3].value = data.seal || '';

        // Jeśli w danych jest lane (kierunek)
        if (data.direction || data.lane) {
            const lane = data.direction || data.lane;
            const dest = lane.includes('->') ? lane.split('->')[1].trim() : lane;
            const sInput = document.getElementById('intro_search');
            if (sInput) {
                sInput.value = dest;
                sInput.dispatchEvent(new Event('input'));
            }
        }

        fields.forEach(f => f.dispatchEvent(new Event('input')));
        chrome.storage.local.set({ nextBasicFieldIndex: 0 });
    }
}

function clearAllFields() {
    ['vrid', 'tractor', 'trailer', 'description', 'seal', 'search', 'consignee', 'nationals'].forEach(id => {
        const el = document.getElementById(`intro_${id}`);
        if (el) el.value = '';
    });
    selectElement.selectedIndex = 0;
    selectElement.classList.remove('visible');
    populateSelect(kierunki);
    document.querySelectorAll('.clear-btn').forEach(btn => btn.style.display = 'none');
    chrome.storage.local.set({ nextBasicFieldIndex: 0 });
}

document.getElementById('btn_clear_all').addEventListener('click', clearAllFields);

// Funkcja parsująca tekst wklejony do VRID
function fillBasicFromText(text) {
    // Podział tekstu na części (separacja spacjami/tabulatorami)
    const rawParts = (text || '').trim().split(/\s+/).filter(Boolean);
    if (rawParts.length === 0) return false;

    const fields = getBasicFields(); // VRID, Tractor, Trailer, Seal
    let usedParts = 0;
    let foundDirection = null;

    // Przeszukaj części w poszukiwaniu wzorca kierunku (np. NUE1->WRO5)
    const cleanedParts = rawParts.filter(part => {
        if (part.includes('->')) {
            foundDirection = part.split('->')[1].trim();
            return false; // Usuń z listy do wypełnienia pól podstawowych
        }
        return true;
    });

    // Wypełnij pola podstawowe (VRID, Ciągnik, Naczepa, Seal)
    fields.forEach((field, i) => {
        if (cleanedParts[i]) {
            field.value = cleanedParts[i];
            field.dispatchEvent(new Event('input'));
            usedParts++;
        }
    });

    // Jeśli znaleziono kierunek, wypełnij intro_search
    if (foundDirection) {
        const sInput = document.getElementById('intro_search');
        if (sInput) {
            sInput.value = foundDirection;
            sInput.dispatchEvent(new Event('input'));
        }
    }

    return usedParts > 0;
}

const introVridEl = document.getElementById('intro_vrid');
if (introVridEl) {
    introVridEl.addEventListener('paste', function (e) {
        const text = (e.clipboardData || window.clipboardData).getData('text');
        if (text && text.trim().split(/\s+/).length > 1) {
            e.preventDefault();
            if (fillBasicFromText(text)) {
                const tractorEl = document.getElementById('intro_tractor');
                if (tractorEl) tractorEl.focus();
            }
        }
    });
}

