function showConfirmModal(message, onConfirm, confirmText = 'TAK', cancelText = 'NIE') {
    const oldModal = document.getElementById('confirm-modal');
    if (oldModal) oldModal.remove();

    const modal = document.createElement('div');
    modal.id = 'confirm-modal';
    modal.className = 'opis-modal';
    const modalContent = document.createElement('div');
    modalContent.className = 'opis-modal-content modal-content-small';
    modalContent.style.borderRadius = '0';

    modalContent.innerHTML = `
        <div class="opis-modal-header"><h3><i class="fas fa-question-circle"></i> Potwierdzenie</h3></div>
        <div class="modal-message">${message}</div>
        <div class="modal-buttons">
            <button class="confirm-button" style="border-radius:0;">${confirmText}</button>
            <button class="cancel-button" style="border-radius:0;">${cancelText}</button>
        </div>
    `;

    modal.appendChild(modalContent);
    document.body.appendChild(modal);

    modal.querySelector('.confirm-button').onclick = () => { modal.remove(); onConfirm(); };
    modal.querySelector('.cancel-button').onclick = () => modal.remove();
}

function showSuccessModal(message) {
    const oldModal = document.getElementById('success-modal');
    if (oldModal) oldModal.remove();

    const modal = document.createElement('div');
    modal.id = 'success-modal';
    modal.className = 'opis-modal';
    const modalContent = document.createElement('div');
    modalContent.className = 'opis-modal-content modal-content-small';
    modalContent.style.borderRadius = '0';

    modalContent.innerHTML = `
        <div class="opis-modal-header">
            <h3 class="success-title"><i class="fas fa-check-circle"></i> Sukces</h3>
            <button class="opis-modal-close" style="border-radius:0;"><img src="https://api.iconify.design/ant-design:close-square-twotone.svg?color=darkgray" style="width: 1.5em; height: 1.5em;"></button>
        </div>
        <div class="modal-message">${message}</div>
        <div class="modal-buttons-single"><button class="ok-button" style="border-radius:0;">OK</button></div>
    `;

    modal.appendChild(modalContent);
    document.body.appendChild(modal);
    modal.querySelector('.ok-button').onclick = () => modal.remove();
    modal.querySelector('.opis-modal-close').onclick = () => modal.remove();
    setTimeout(() => { if (document.body.contains(modal)) modal.remove(); }, 3000);
}

