function setTheme(theme) {
    document.documentElement.setAttribute('theme', theme);
    localStorage.setItem('cmr_theme', theme);
    const themeToggleBtn = document.getElementById('theme-toggle');
    themeToggleBtn.innerHTML = theme === 'dark' ? '<img src="https://api.iconify.design/duo-icons:sun.svg" alt="theme">' : '<img src="https://api.iconify.design/duo-icons:moon-stars.svg" alt="theme">';
}

document.getElementById('theme-toggle').onclick = () => setTheme(document.documentElement.getAttribute('theme') === 'dark' ? 'light' : 'dark');
setTheme(localStorage.getItem('cmr_theme') || 'dark');

document.addEventListener("DOMContentLoaded", function () {
    chrome.storage.onChanged.addListener((changes, areaName) => {
        if (areaName !== 'local') return;
        if (changes.clearAfterPrint && changes.clearAfterPrint.newValue === true) clearAllFields();
        if (changes.pasteFromPage && changes.pasteFromPage.newValue) {
            var payload = changes.pasteFromPage.newValue;
            chrome.storage.local.remove('pasteFromPage');
            applyPasteFromPage(payload);
        }
    });

    chrome.storage.local.get('pasteFromPage', (result) => {
        if (result.pasteFromPage) {
            applyPasteFromPage(result.pasteFromPage);
            chrome.storage.local.remove('pasteFromPage');
        }
    });
});

